import MockAdapter from "axios-mock-adapter";
import { mockData } from "./mockData";

export const setupMock = (api) => {
  const mock = new MockAdapter(api, { delayResponse: 100 });

  console.log("Setting up Robust Mock API...");

  // Use a function-based router for maximum reliability with query params and base URLs
  mock.onAny().reply((config) => {
    const url = config.url || "";
    const method = config.method?.toLowerCase();

    // --- Authentication ---
    if (method === "post" && url.includes("/login")) {
      return [200, { access_token: "mock-token-123", user: mockData.user }];
    }
    if (url.includes("/user") && !url.includes("/admin")) {
      if (url.endsWith("/user")) return [200, { user: mockData.user }];
      if (url.includes("/header-data")) return [200, mockData.header_data];
      if (url.includes("/statistics")) return [200, mockData.statistics];
      if (url.includes("/notifications")) return [200, mockData.notifications];
      if (url.includes("/messages")) return [200, mockData.messages];
      if (url.includes("/favorites"))
        return [200, { data: mockData.products.slice(0, 2) }];
      if (url.includes("/cart"))
        return [200, { data: mockData.products.slice(0, 1) }];
      if (method === "post" && url.includes("/orders"))
        return [200, { order: mockData.orders[0] }];
    }

    // --- Admin Endpoints (Dashboard Tables) ---
    if (url.includes("/admin/")) {
      if (url.includes("/purchases/statistics")) {
        return [
          200,
          {
            totalPurchases: 225000,
            monthlyPurchases: 50000,
            activeSuppliers: 12,
            pendingBills: 4,
          },
        ];
      }
      if (url.endsWith("/admin/statistics") || url === "/admin/statistics")
        return [200, mockData.statistics];
      if (url.includes("/analytics/overview"))
        return [200, mockData.analytics_overview];
      if (url.includes("/analytics/products"))
        return [200, mockData.analytics_products];
      if (url.includes("/users")) return [200, mockData.users];
      if (url.includes("/products")) return [200, mockData.products];
      if (url.includes("/categories")) return [200, mockData.categories];
      if (url.includes("/brands")) return [200, mockData.brands];
      if (url.includes("/orders")) return [200, mockData.orders];
      if (url.includes("/posts")) return [200, mockData.posts];
      if (url.includes("/transactions")) return [200, mockData.transactions];
      if (url.includes("/return-requests"))
        return [200, mockData.return_requests];
      if (url.includes("/coupons")) return [200, mockData.coupons];
      if (url.includes("/reviews")) return [200, mockData.reviews];
      if (url.includes("/staff")) return [200, mockData.staff];
      if (url.includes("/purchases")) return [200, mockData.purchases];
      if (url.includes("/suppliers")) return [200, mockData.suppliers];
      if (url.includes("/inventory/logs") || url.includes("/inventory-logs"))
        return [200, mockData.inventory_logs];
      if (url.includes("/affiliates") || url.includes("/tagers"))
        return [200, mockData.affiliates];
      if (url.includes("/shipping-zones"))
        return [200, mockData.shipping_zones];
      if (url.includes("/banners")) return [200, mockData.banners];
      if (url.includes("/settings") || url.includes("/store-settings"))
        return [200, mockData.settings];
      if (url.includes("/governorates"))
        return [
          200,
          [
            { id: 1, name: "القاهرة" },
            { id: 2, name: "الجيزة" },
          ],
        ];
      if (url.includes("/shipping-methods")) return [200, []];
      if (url.includes("/financials"))
        return [200, { revenue: 1250000, profit: 350000 }];

      // Admin Catch-all for POST/PUT/DELETE
      if (method === "post" || method === "put" || method === "delete") {
        return [
          200,
          { success: true, message: "تمت العملية بنجاح في وضع الديمو" },
        ];
      }
    }

    // --- Storefront ---
    if (url.includes("/products")) {
      if (url.includes("/best-sellers"))
        return [200, mockData.products.slice(0, 6)];
      if (url.includes("/flash-deals"))
        return [200, mockData.products.slice(2, 8)];
      if (url.match(/\/products\/\d+/)) {
        const id = parseInt(url.split("/").pop());
        return [
          200,
          mockData.products.find((p) => p.id === id) || mockData.products[0],
        ];
      }
      return [200, { data: mockData.products }];
    }

    if (url.includes("/categories"))
      return [200, { data: mockData.categories }];
    if (url.includes("/brands")) return [200, mockData.brands];
    if (url.includes("/settings")) return [200, mockData.settings];
    if (url.includes("/banners")) return [200, mockData.banners];
    if (url.includes("/governorates")) return [200, mockData.governorates];
    if (url.includes("/shipping-methods"))
      return [200, mockData.shipping_methods];
    if (url.includes("/apply-coupon"))
      return [
        200,
        {
          success: true,
          discount_amount: 100,
          message: "تم تطبيق الكوبون بنجاح",
        },
      ];
    if (url.includes("/user/statistics"))
      return [200, mockData.user_statistics];

    // --- Global Fallback ---
    console.warn(`Mock API Fallback for: [${method}] ${url}`);
    if (method === "get") {
      // Return empty array for lists, or empty object for others
      if (url.includes("/admin/") || url.includes("/user/")) return [200, []];
      return [200, { data: [] }];
    }
    return [200, { success: true }];
  });

  console.log("Robust Mock API Ready.");
};
